#include <iostream>
#include <vector>
using namespace std;

// Abstract Base Class
class Shape {
public:
    virtual void draw() = 0; // Pure virtual
    virtual ~Shape() {} // Virtual Destructor (Important!)
};

class Circle : public Shape {
public:
    void draw() override {
        cout << "Drawing a Circle 🔴" << endl;
    }
};

class Square : public Shape {
public:
    void draw() override {
        cout << "Drawing a Square 🟥" << endl;
    }
};

int main() {
    // Vector of pointers to generic Shapes
    vector<Shape*> shapes;

    shapes.push_back(new Circle());
    shapes.push_back(new Square());
    shapes.push_back(new Circle());

    cout << "--- Rendering Scene ---\n";

    // Polymorphic call
    for(Shape* s : shapes) {
        s->draw(); // Calls the correct draw() for each object
    }

    // Cleanup
    for(Shape* s : shapes) delete s;

    return 0;
}
